        properties:
          entryfilePath: src/api.ts
      events:
        - type: http-api-gateway
          properties:
            httpApiGatewayName: httpApi
            method: GET
            path: /orders
            authorizer:
              type: lambda
              properties:
                functionName: authorizerFunction
                identitySources:
                  - $request.header.Authorization
