   properties:
     packaging:
       type: stacktape-image-buildpack
       properties:
         entryfilePath: src/server.ts
         customDockerBuildCommands:
           - apt-get update && apt-get install -y poppler-utils
           - fc-cache -f
     resources:
       cpu: 1
       memory: 2048
```

