   type: worker-service
   properties:
     packaging:
       type: nixpacks
       properties:
         sourceDirectoryPath: ./worker
         phases:
           - name: install
             cmds:
               - npm ci
           - name: build
             cmds:
               - npm run build
     resources:
       cpu: 0.5
       memory: 1024
```

