api:
  type: http-api-gateway
  properties:
    cdn:
      enabled: true
      routeRewrites:
        - path: /assets/*
          routeTo:
            type: bucket
            properties:
              bucketName: assets
assets:
  type: bucket
  properties:
    directoryUpload:
      directoryPath: ./public
```

**Example (TypeScript):**

```ts
