export default defineConfig(() => {
const assets = new Bucket({
  directoryUpload: { directoryPath: './public' }
});
const api = new HttpApiGateway({
  cdn: {
    enabled: true,
    routeRewrites: [
      {
        path: '/assets/*',
        routeTo: { type: 'bucket', properties: { bucketName: 'assets' } }
      }
    ]
  }
});
return { resources: { assets, api } };
});
```

