      properties: {
        entryfilePath: 'src/payments.ts'
      }
    },
    port: 3000,
    resources: {
      cpu: 1,
      memory: 1024
    },
    loadBalancing: {
      type: 'application-load-balancer'
    }
  });

  return { resources: { paymentsService } };
});
```

