---

**Example (YAML):**

```yaml
resources:
  myBucket:
    type: bucket
    properties:
      enableEventBusNotifications: true
      versioning: true
```

**Example (TypeScript):**

```ts
import { Bucket, defineConfig } from 'stacktape';

export default defineConfig(() => {
  const myBucket = new Bucket({
    enableEventBusNotifications: true,
    versioning: true
  });
  return { resources: { myBucket } };
});
```

