fileOptions.description:
#### Set HTTP headers or tags on files matching specific patterns.

---

**Example (YAML):**

```yaml
resources:
  assetsBucket:
    type: bucket
    properties:
      directoryUpload:
        directoryPath: ./dist
        fileOptions:
          - includePattern: '*.html'
            headers:
              - key: Cache-Control
                value: no-cache
      cdn:
        enabled: true
```

**Example (TypeScript):**

```ts
import { Bucket, defineConfig } from 'stacktape';

export default defineConfig(() => {
  const assetsBucket = new Bucket({
    directoryUpload: {
      directoryPath: './dist',
      fileOptions: [
        {
          includePattern: '*.html',
          headers: [{ key: 'Cache-Control', value: 'no-cache' }]
        }
      ]
    },
    cdn: {
      enabled: true
    }
  });
  return { resources: { assetsBucket } };
});
```

