resources:
api:
  type: http-api-gateway
  properties:
    cdn:
      enabled: true
      defaultRoutePrefix: /v2
```

**Example (TypeScript):**

```ts
import { HttpApiGateway, defineConfig } from 'stacktape';

export default defineConfig(() => {
