    type: user-auth-pool
    properties:
      allowOnlyAdminsToCreateAccount: true
      allowPhoneNumberAsUserName: true
      inviteMessageConfig:
        emailSubject: Welcome to Acme
        emailMessage: 'Hi {username}, your temporary password is {####}.'
        smsMessage: 'Acme login: {username} / {####}'
```

