```ts
import { UserAuthPool, defineConfig } from 'stacktape';

export default defineConfig(() => {
  const userPool = new UserAuthPool({
    userVerificationType: 'email-code',
    schema: [
      {
        name: 'plan',
        attributeDataType: 'String',
        mutable: true
      }
    ]
  });
  return { resources: { userPool } };
});
```

