  orderEventsQueue:
    type: sqs-queue
    properties:
      fifoEnabled: true
      contentBasedDeduplication: true
      visibilityTimeoutSeconds: 90
  orderEventConsumer:
    type: function
    properties:
      packaging:
        type: stacktape-lambda-buildpack
        properties:
          entryfilePath: src/order-event-consumer.ts
      events:
        - type: sqs
          properties:
            sqsQueueName: orderEventsQueue
```

