          minTTL: 0
          defaultTTL: 60
          maxTTL: 3600
        pathCachingOverrides:
          - path: /_server-islands/*
            cachingOptions:
              defaultTTL: 300
```

**Example (TypeScript):**

```ts
import { NextjsWeb, defineConfig } from 'stacktape';

