      disableInvalidationAfterDeploy: false,
      defaultCachingOptions: {
        minTTL: 0,
        defaultTTL: 60,
        maxTTL: 3600
      },
      pathCachingOverrides: [
        {
          path: '/_server-islands/*',
          cachingOptions: { defaultTTL: 300 }
        }
      ]
    }
  });
  return { resources: { web } };
});
```

