    }
  });
  const smokeTest = new LambdaFunction({
    packaging: { type: 'stacktape-lambda-buildpack', properties: { entryfilePath: 'src/smoke-test.ts' } }
  });
  return { resources: { paymentApi, smokeTest } };
});
```

