  imageProcessor:
    type: function
    properties:
      packaging:
        type: stacktape-lambda-buildpack
        properties:
          entryfilePath: ./src/process-image.ts
      timeout: 30
      alarms:
        - description: Image processing approaching timeout
          trigger:
            type: lambda-duration
            properties:
              thresholdMilliseconds: 25000
              statistic: max
```

