        - database
      environment:
        - name: DATABASE_URL
          value: $ResourceParam('database', 'connectionString')
        - name: STRIPE_SECRET_KEY
          value: $Secret('stripe.secretKey')
        - name: PUBLIC_APP_NAME
          value: My Storefront
